values
  ('40000000-0000-4000-8000-000000003e85', '30000000-0000-4000-8000-000000000fa1', 'A non-random process shift (Rule of Seven) requiring root-cause investigation for assignable cause variation.', 1),
  ('40000000-0000-4000-8000-000000003e86', '30000000-0000-4000-8000-000000000fa1', 'Normal random process variation that should be ignored.', 2),
  ('40000000-0000-4000-8000-000000003e87', '30000000-0000-4000-8000-000000000fa1', 'Immediate proof that the manufacturing machine has reached 6 Sigma perfection.', 3),
  ('40000000-0000-4000-8000-000000003e88', '30000000-0000-4000-8000-000000000fa1', 'A failure of the statistical software calculating the control limits.', 4),
  ('40000000-0000-4000-8000-000000003e89', '30000000-0000-4000-8000-000000000fa2', 'Quality Control (QC) because it measures final product bug counts in production.', 1),
  ('40000000-0000-4000-8000-000000003e8a', '30000000-0000-4000-8000-000000000fa2', 'Quality Assurance (QA) because it focuses on process adherence to prevent defect creation.', 2),
  ('40000000-0000-4000-8000-000000003e8b', '30000000-0000-4000-8000-000000000fa2', 'Neither QA nor QC; this is strictly financial auditing.', 3),
  ('40000000-0000-4000-8000-000000003e8c', '30000000-0000-4000-8000-000000000fa2', 'Total Productive Maintenance (TPM).', 4),
  ('40000000-0000-4000-8000-000000003e8d', '30000000-0000-4000-8000-000000000fa3', 'Kanban pull scheduling.', 1),
  ('40000000-0000-4000-8000-000000003e8e', '30000000-0000-4000-8000-000000000fa3', 'Heijunka production leveling.', 2),
  ('40000000-0000-4000-8000-000000003e8f', '30000000-0000-4000-8000-000000000fa3', 'Jidoka (Autonomation / Quality at the source).', 3),
  ('40000000-0000-4000-8000-000000003e90', '30000000-0000-4000-8000-000000000fa3', '5S Workplace Standardization.', 4),
  ('40000000-0000-4000-8000-000000003e91', '30000000-0000-4000-8000-000000000fa4', 'Plotting project activity schedules on a time-phased Gantt chart.', 1),
